package com.angrybirds.entities;

import com.angrybirds.physics.PhysicsWorld;
import com.badlogic.gdx.graphics.Color;
import com.badlogic.gdx.graphics.Pixmap;
import com.badlogic.gdx.graphics.Texture;
import com.badlogic.gdx.graphics.g2d.SpriteBatch;
import com.badlogic.gdx.math.Vector2;
import com.badlogic.gdx.physics.box2d.Body;

public class Block {
    public enum BlockType { WOOD, ICE }

    private Body body;
    private Texture texture;
    private float width;
    private float height;
    private Vector2 visualPosition;
    private BlockType type;

    public Block(PhysicsWorld physicsWorld, float x, float y, float width, float height, boolean isDynamic) {
        this(physicsWorld, x, y, width, height, isDynamic, BlockType.WOOD);
    }

    public Block(PhysicsWorld physicsWorld, float x, float y, float width, float height, boolean isDynamic, BlockType type) {
        this.width = width;
        this.height = height;
        this.type = type;
        this.body = physicsWorld.createBlockBody(x, y, width, height, isDynamic);
        this.visualPosition = new Vector2(x, y);

        // Create texture based on block type
        Pixmap pixmap = new Pixmap((int)width, (int)height, Pixmap.Format.RGBA8888);

        if (type == BlockType.ICE) {
            // Light blue/cyan color for ice blocks
            pixmap.setColor(new Color(0.7f, 0.9f, 1.0f, 0.8f)); // Light blue
            pixmap.fill();
            pixmap.setColor(new Color(0.5f, 0.8f, 1.0f, 1.0f)); // Darker blue border
            pixmap.drawRectangle(0, 0, (int)width, (int)height);
            // Add some ice pattern
            pixmap.setColor(new Color(1.0f, 1.0f, 1.0f, 0.6f)); // White highlights
            if (width > 20) pixmap.drawLine(5, 5, (int)width - 5, (int)height - 5);
        } else {
            // Brown color for wood blocks
            pixmap.setColor(new Color(0.5f, 0.3f, 0.1f, 1f)); // Brown
            pixmap.fill();
            pixmap.setColor(new Color(0.3f, 0.15f, 0.05f, 1f)); // Darker brown border
            pixmap.drawRectangle(0, 0, (int)width, (int)height);
            // Add wood texture
            pixmap.setColor(new Color(0.4f, 0.2f, 0.0f, 0.5f)); // Dark lines for wood grain
            for (int i = 0; i < height; i += 10) {
                pixmap.drawLine(0, i, (int)width, i);
            }
        }

        this.texture = new Texture(pixmap);
        pixmap.dispose();
    }

    public void update() {
        visualPosition.set(body.getPosition().x * PhysicsWorld.PPM, body.getPosition().y * PhysicsWorld.PPM);
    }

    public void draw(SpriteBatch batch) {
        float x = visualPosition.x - width / 2;
        float y = visualPosition.y - height / 2;
        float rotation = body.getAngle() * com.badlogic.gdx.math.MathUtils.radiansToDegrees;

        batch.draw(texture, x, y, width / 2, height / 2, width, height, 1, 1, rotation, 0, 0, texture.getWidth(), texture.getHeight(), false, false);
    }

    public Body getBody() {
        return body;
    }

    public void dispose() {
        texture.dispose();
    }
}

package com.angrybirds.entities;

import com.angrybirds.physics.PhysicsWorld;
import com.badlogic.gdx.graphics.Color;
import com.badlogic.gdx.graphics.Pixmap;
import com.badlogic.gdx.graphics.Texture;
import com.badlogic.gdx.graphics.g2d.SpriteBatch;
import com.badlogic.gdx.math.Vector2;
import com.badlogic.gdx.physics.box2d.Body;

public class Pig {
    private Body body;
    private Texture texture;
    private float radius;
    private Vector2 visualPosition;

    public Pig(PhysicsWorld physicsWorld, float x, float y, float radius) {
        this.radius = radius;
        this.body = physicsWorld.createPigBody(x, y, radius);
        this.visualPosition = new Vector2(x, y);

        // Create a detailed pig texture with face
        int size = (int)radius * 2 + 2;
        Pixmap pixmap = new Pixmap(size, size, Pixmap.Format.RGBA8888);
        int center = (int)radius + 1;
        int r = (int)radius;

        // Main body - pink circle
        pixmap.setColor(new Color(1.0f, 0.75f, 0.85f, 1.0f)); // Pink
        pixmap.fillCircle(center, center, r);

        // Snout - darker pink circle at bottom
        pixmap.setColor(new Color(0.95f, 0.65f, 0.75f, 1.0f)); // Darker pink
        pixmap.fillCircle(center, center - r/3, (int)(r * 0.4f));

        // Snout nostrils
        pixmap.setColor(Color.BLACK);
        int nostrilRadius = Math.max(1, (int)(r * 0.08f));
        pixmap.fillCircle(center - (int)(r * 0.15f), center - r/3, nostrilRadius);
        pixmap.fillCircle(center + (int)(r * 0.15f), center - r/3, nostrilRadius);

        // Eyes - black circles
        int eyeRadius = Math.max(1, (int)(r * 0.15f));
        pixmap.setColor(Color.BLACK);
        pixmap.fillCircle(center - (int)(r * 0.3f), center + (int)(r * 0.2f), eyeRadius);
        pixmap.fillCircle(center + (int)(r * 0.3f), center + (int)(r * 0.2f), eyeRadius);

        // Eye highlights - white
        pixmap.setColor(Color.WHITE);
        int highlightRadius = Math.max(1, (int)(r * 0.06f));
        pixmap.fillCircle(center - (int)(r * 0.25f), center + (int)(r * 0.25f), highlightRadius);
        pixmap.fillCircle(center + (int)(r * 0.35f), center + (int)(r * 0.25f), highlightRadius);

        // Ears - small circles on top
        pixmap.setColor(new Color(1.0f, 0.75f, 0.85f, 1.0f)); // Pink
        int earRadius = Math.max(1, (int)(r * 0.2f));
        pixmap.fillCircle(center - (int)(r * 0.4f), center + (int)(r * 0.7f), earRadius);
        pixmap.fillCircle(center + (int)(r * 0.4f), center + (int)(r * 0.7f), earRadius);

        // Inner ear - lighter pink
        pixmap.setColor(new Color(1.0f, 0.85f, 0.95f, 1.0f)); // Light pink
        pixmap.fillCircle(center - (int)(r * 0.4f), center + (int)(r * 0.7f), Math.max(1, (int)(r * 0.1f)));
        pixmap.fillCircle(center + (int)(r * 0.4f), center + (int)(r * 0.7f), Math.max(1, (int)(r * 0.1f)));

        // Outline
        pixmap.setColor(Color.BLACK);
        pixmap.drawCircle(center, center, r);

        this.texture = new Texture(pixmap);
        pixmap.dispose();
    }

    public void update() {
        visualPosition.set(body.getPosition().x * PhysicsWorld.PPM, body.getPosition().y * PhysicsWorld.PPM);
    }

    public void draw(SpriteBatch batch) {
        float x = visualPosition.x - radius;
        float y = visualPosition.y - radius;
        float rotation = body.getAngle() * com.badlogic.gdx.math.MathUtils.radiansToDegrees;

        batch.draw(texture, x, y, radius, radius, radius * 2, radius * 2, 1, 1, rotation, 0, 0, texture.getWidth(), texture.getHeight(), false, false);
    }

    public Body getBody() {
        return body;
    }

    public void dispose() {
        texture.dispose();
    }
}

package com.angrybirds.entities;

import com.badlogic.gdx.graphics.Color;
import com.badlogic.gdx.graphics.Pixmap;
import com.badlogic.gdx.graphics.Texture;
import com.badlogic.gdx.graphics.g2d.SpriteBatch;
import com.badlogic.gdx.math.Vector2;

public class Slingshot {
    private Vector2 position;
    private Bird currentBird;
    private Texture baseTexture;
    private float maxPullDistance = 100f;
    private float launchStrength = 5.0f;

    public Slingshot(float x, float y) {
        this.position = new Vector2(x, y);

        // Create a simple brown rectangle as placeholder for slingshot base
        Pixmap pixmap = new Pixmap(20, 100, Pixmap.Format.RGBA8888);
        pixmap.setColor(new Color(0.5f, 0.3f, 0.1f, 1f));
        pixmap.fill();
        this.baseTexture = new Texture(pixmap);
        pixmap.dispose();
    }

    public void setBird(Bird bird) {
        this.currentBird = bird;
        if (bird != null) {
            bird.setVisualPosition(position.x, position.y + 80);
        }
    }

    public void draw(SpriteBatch batch) {
        batch.draw(baseTexture, position.x - 10, position.y);

        // Draw elastic if bird is being pulled
        if (currentBird != null && currentBird.getState() == Bird.State.ON_SLINGSHOT) {
            // In a real game, we would draw lines from the slingshot arms to the bird
        }
    }

    public void pullBird(Vector2 touchCoords) {
        if (currentBird == null || currentBird.getState() != Bird.State.ON_SLINGSHOT) return;

        Vector2 anchor = new Vector2(position.x, position.y + 80);
        Vector2 pull = touchCoords.cpy().sub(anchor);

        if (pull.len() > maxPullDistance) {
            pull.setLength(maxPullDistance);
        }

        currentBird.setVisualPosition(anchor.x + pull.x, anchor.y + pull.y);
    }

    public void releaseBird() {
        if (currentBird == null || currentBird.getState() != Bird.State.ON_SLINGSHOT) return;

        Vector2 anchor = new Vector2(position.x, position.y + 80);
        Vector2 birdPos = currentBird.getVisualPosition();
        Vector2 impulse = anchor.cpy().sub(birdPos).scl(launchStrength);

        currentBird.launch(impulse);
    }

    public boolean isTouchOnBird(Vector2 touchCoords) {
        if (currentBird == null) return false;
        return touchCoords.dst(currentBird.getVisualPosition()) < currentBird.getRadius() * 2;
    }

    public void dispose() {
        baseTexture.dispose();
    }
}

